#!/usr/bin/env node

import fs from "node:fs/promises";
import path from "node:path";

const PROJECT_ROOT = process.cwd();
const ENGLISH_SOURCE_PATH = path.join(PROJECT_ROOT, "index.html");
const ARABIC_SOURCE_PATH = path.join(PROJECT_ROOT, "ar.html");
const OUTPUT_DIR = path.join(PROJECT_ROOT, "src", "lib", "generated");
const OUTPUT_PATH = path.join(OUTPUT_DIR, "landing-page-content.ts");

function buildModuleSource(englishHtml, arabicHtml) {
  return `// Auto-generated by scripts/generate-landing-content.mjs.
// Do not edit this file manually.

export const LANDING_PAGE_HTML = {
  en: ${JSON.stringify(englishHtml)},
  ar: ${JSON.stringify(arabicHtml)},
} as const;
`;
}

async function writeIfChanged(filePath, content) {
  let existing = null;
  try {
    existing = await fs.readFile(filePath, "utf8");
  } catch (error) {
    if (error && error.code !== "ENOENT") {
      throw error;
    }
  }

  if (existing === content) {
    return false;
  }

  await fs.writeFile(filePath, content, "utf8");
  return true;
}

async function readFileOrNull(filePath) {
  try {
    return await fs.readFile(filePath, "utf8");
  } catch (error) {
    if (error && error.code === "ENOENT") {
      return null;
    }
    throw error;
  }
}

async function exists(filePath) {
  try {
    await fs.access(filePath);
    return true;
  } catch {
    return false;
  }
}

async function main() {
  const [englishHtml, arabicHtml] = await Promise.all([
    readFileOrNull(ENGLISH_SOURCE_PATH),
    readFileOrNull(ARABIC_SOURCE_PATH),
  ]);

  if (!englishHtml || !arabicHtml) {
    const generatedExists = await exists(OUTPUT_PATH);
    if (generatedExists) {
      console.log(
        `Source HTML files are unavailable. Using existing ${path.relative(PROJECT_ROOT, OUTPUT_PATH)}`,
      );
      return;
    }

    throw new Error(
      [
        "Landing source files are missing and no generated bundle exists.",
        `Expected: ${path.relative(PROJECT_ROOT, ENGLISH_SOURCE_PATH)}`,
        `Expected: ${path.relative(PROJECT_ROOT, ARABIC_SOURCE_PATH)}`,
        `Missing: ${path.relative(PROJECT_ROOT, OUTPUT_PATH)}`,
      ].join("\n"),
    );
  }

  await fs.mkdir(OUTPUT_DIR, { recursive: true });
  const source = buildModuleSource(englishHtml, arabicHtml);
  const changed = await writeIfChanged(OUTPUT_PATH, source);

  if (changed) {
    console.log(`Generated ${path.relative(PROJECT_ROOT, OUTPUT_PATH)}`);
    return;
  }

  console.log(`No changes in ${path.relative(PROJECT_ROOT, OUTPUT_PATH)}`);
}

main().catch((error) => {
  console.error(error);
  process.exit(1);
});
